#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=3e5+10,INF=0x3f3f3f3f;typedef long long ll;
vector<int> G[N];int siz[N],mxs[N],n,dfn[N],cdt,t[N],loc[N];ll ans;
template<typename T> inline void Clear(vector<T> &v){vector<T> t;v.swap(t);}
inline void add(int p,int w){while(p<=n)t[p]+=w,p+=(p&-p);}
inline int qry(int l,int r)
{
	l=max(l-1,0);r=max(r,0);r=min(r,n);int ans=0;
	while(l)ans-=t[l],l^=(l&-l);
	while(r)ans+=t[r],r^=(r&-r);
	return ans;
	
}
int Rt,cnt;inline void GetRt(int u,int fa=0)
{
	dfn[u]=++cdt;siz[u]=1;mxs[u]=0;loc[cdt]=u;
	for(int v:G[u])if(v!=fa)
	{
		GetRt(v,u);siz[u]+=siz[v];
		mxs[u]=max(mxs[u],siz[v]);
	}
	if(max(mxs[u],n-siz[u])<=(n>>1))Rt=u;
}
struct Qy{int l,r,k;};vector<Qy> Q[N];int pm[N],sm[N],kk[N];
inline void dfs(int u,int fa=0)
{
//	printf("dfs %d\n",u);
	for(int v:G[u])if(v!=fa){add(siz[v],1);dfs(v,u);add(siz[v],-1);}
	if(!fa)return;
	ans+=1ll*u*qry(2*mxs[u],2*siz[u]);
	kk[u]+=qry(2*mxs[u],2*siz[u]);
	ans-=1ll*u*qry(n-2*siz[u],n-2*mxs[u]);
	kk[u]-=qry(n-2*siz[u],n-2*mxs[u]);
	if(siz[u]==1)return;
	Q[dfn[u]].push_back({n-2*siz[u],n-2*mxs[u],+u});
	Q[dfn[u]+siz[u]-1].push_back({n-2*siz[u],n-2*mxs[u],-u});
}
int main()
{
	int T=read();Begin:
	
	ans=0;n=read();rep(0,n+3,i)Clear(G[i]),Clear(Q[i]);
	memset(t+1,0,n*sizeof(int));cdt=0;
	memset(loc,0,sizeof(loc));
	rep(2,n,i)
	{
		int x=read(),y=read();
		G[x].push_back(y);
		G[y].push_back(x);
	}
	GetRt(1);cdt=0;GetRt(Rt);
//	rep(1,n,i)printf("%d ",siz[i]);puts("");
//	rep(1,n,i)printf("%d ",mxs[i]);puts("");
	dfs(Rt);
	rep(1,n,i)add(siz[i],1);
	rep(1,n,u)if(u!=Rt)
	{
		ans-=1ll*u*(n-2*siz[u]<=n&&n<=n-2*mxs[u]);//kk[u]-=(n-2*siz[u]<=n&&n<=n-2*mxs[u]);
		ans+=1ll*u*qry(n-2*siz[u],n-2*mxs[u]);//kk[u]+=qry(n-2*siz[u],n-2*mxs[u]);
//		printf("%d :: %lld\n",u,ans); 
	}
	memset(pm,0,sizeof(pm));
	memset(sm,0,sizeof(sm));
	pm[0]=siz[G[Rt][0]];
	for(unsigned i=1;i<G[Rt].size();++i) pm[i]=max(pm[i-1],siz[G[Rt][i]]);
	for(unsigned i=G[Rt].size()-1;~i;--i)sm[i]=max(sm[i+1],siz[G[Rt][i]]);
	for(unsigned i=0;i<G[Rt].size();++i)
	{
		int mxs=0;if(i!=0)mxs=max(mxs,pm[i-1]);
		if(i!=G[Rt].size()-1)mxs=max(mxs,sm[i+1]);
		int u=G[Rt][i];rep(dfn[u],dfn[u]+siz[u]-1,j)
		{
			int v=loc[j];if(max(mxs,siz[u]-siz[v])<=(n-siz[v])>>1)ans+=Rt;
		}
	}
	memset(t+1,0,n*sizeof(int));
	rep(1,n,i)
	{
		add(siz[loc[i]],1);
		for(Qy v:Q[i])ans+=1ll*v.k*qry(v.l,v.r);
	}
	printf("%lld\n",ans);
	
	if(--T)goto Begin;return 0;
}
